const root = $input.item.json ?? {};
const body = root.body && typeof root.body === 'object' ? root.body : {};
const pick = (k) => (body[k] !== undefined ? body[k] : root[k]);

const toStr = (v) => {
  if (v === undefined || v === null) return null;
  return String(v).trim();
};

const toBool = (v, fallback = false) => {
  if (typeof v === 'boolean') return v;
  if (typeof v === 'number') return v === 1;
  if (typeof v === 'string') {
    const s = v.trim().toLowerCase();
    if (['true','1','si','sí','yes'].includes(s)) return true;
    if (['false','0','no'].includes(s)) return false;
  }
  return fallback;
};

const allowedChannels = new Set(['web','email','mercurio','form','phone','whatsapp']);
const rawChannel = (toStr(pick('source_channel')) || 'web').toLowerCase();
const source_channel = allowedChannels.has(rawChannel) ? rawChannel : 'web';

const subject = toStr(pick('subject')) || '';
const description = toStr(pick('description')) || '';
const raw_text = toStr(pick('raw_text')) || description;

return {
  source_channel,
  citizen_name: toStr(pick('citizen_name')),
  is_anonymous: toBool(pick('is_anonymous'), false),
  document_id: toStr(pick('document_id')),
  email: toStr(pick('email')),
  phone: toStr(pick('phone')),
  subject,
  description,
  raw_text,
  attachments: Array.isArray(pick('attachments')) ? pick('attachments') : [],
  location_text: toStr(pick('location_text')),
  consent_data: toBool(pick('consent_data'), false),
  created_at: toStr(pick('created_at')) || new Date().toISOString(),

  // Campos extra para pruebas/control de deduplicado
  test_case: toStr(pick('test_case')),
  source_hash_override: toStr(pick('source_hash_override')),
  expected_branch: toStr(pick('expected_branch')),
  tenant_id: toStr(pick('tenant_id')),
};

const it = $input.item.json;
const errors = [];
const allowedChannels = new Set(['web','email','mercurio','form','phone','whatsapp']);
if (!allowedChannels.has(it.source_channel)) errors.push('source_channel inválido');
if (typeof it.is_anonymous !== 'boolean') errors.push('is_anonymous debe ser booleano');
if (typeof it.consent_data !== 'boolean') errors.push('consent_data debe ser booleano');
if (!it.subject || it.subject.length === 0) errors.push('subject vacío');
if (!it.description || it.description.length === 0) errors.push('description vacía');
if (!it.raw_text || it.raw_text.length === 0) errors.push('raw_text vacío');
if (!it.created_at || isNaN(Date.parse(it.created_at))) errors.push('created_at no es ISO 8601');
if (!Array.isArray(it.attachments)) errors.push('attachments debe ser arreglo');
if (!it.consent_data) errors.push('consent_data debe ser true (Ley 1581/2012)');
if (it.raw_text && it.raw_text.length > 10000) errors.push('raw_text excede 10000 caracteres');
return { ...it, _schema_errors: errors, _schema_ok: errors.length === 0 };

const crypto = require('crypto');
const it = $input.item.json;
const CHANNEL_MAP = { web:'web', form:'web', email:'email', mercurio:'mercurio_csv', phone:'verbal', whatsapp:'social_manual' };
const channel = CHANNEL_MAP[it.source_channel] ?? 'web';
const issuedAt = new Date(it.created_at);
const yyyymmdd = issuedAt.toISOString().slice(0,10).replace(/-/g,'');
const suffix = crypto.randomBytes(3).toString('hex').toUpperCase();
const radicado = `MED-${yyyymmdd}-${suffix}`;

const normalized = (it.raw_text || '').replace(/\s+/g,' ').trim().toLowerCase();
const hashInput = [normalized, it.email ?? '', it.document_id ?? '', it.phone ?? ''].join('|');
const computedHash = crypto.createHash('sha256').update(hashInput).digest('hex');

const override = String(it.source_hash_override ?? '').trim();
const source_hash = (override && override !== 'undefined' && override !== 'null') ? override : computedHash;

const tenantCandidate = String(it.tenant_id ?? '').trim();
const tenant_id = (tenantCandidate && tenantCandidate !== 'undefined' && tenantCandidate !== 'null')
  ? tenantCandidate
  : '00000000-0000-0000-0000-000000000001';

return { ...it, channel, radicado, source_hash, tenant_id, issued_at: issuedAt.toISOString() };

const it = $input.item.json;
const raw_text = it.raw_text;
const display_text = String(raw_text).replace(/\r\n?/g, '\n').replace(/[\t\f\v]+/g, ' ').replace(/[ ]{2,}/g, ' ').replace(/\n{3,}/g, '\n\n').trim();
let llm_text = display_text;
llm_text = llm_text.replace(/[\w.+-]+@[\w-]+\.[\w.-]+/g, '[EMAIL]');
llm_text = llm_text.replace(/(?<!\d)(?:\+?57[\s-]?)?3\d{2}[\s-]?\d{3}[\s-]?\d{4}(?!\d)/g, '[PHONE]');
llm_text = llm_text.replace(/\b(?:CC|C\.C\.|TI|T\.I\.|CE|C\.E\.|NIT)\s*[:.-]?\s*\d[\d.\-]{5,14}/gi, '[DOC]');
llm_text = llm_text.replace(/(?<!\d)\d{6,11}(?!\d)/g, '[DOC]');
llm_text = llm_text.replace(/(?:cra|carrera|cl|calle|av|avenida|tv|transversal|dg|diagonal)\s*[\d#\-\sa-zA-Z]{2,30}/gi, '[DIRECCION]');
return { ...it, raw_text, display_text, llm_text };

const base = $('Format Preserve (raw/display/llm)').item.json;
const rows = $input.all().map(i => i.json).filter(r => r && r.id);
const dup = rows.length > 0 ? rows[0] : null;
return [{ ...base, is_duplicate: !!dup, duplicate_of: dup ? { id: dup.id, radicado: dup.radicado, status: dup.status } : null }];

