Descripción (texto sin PII):
{{ $json.llm_text }}

Ubicación declarada: {{ $json.location_text || 'no especificada' }}
Anónimo: {{ $json.is_anonymous }}
Tiene contacto verificable: {{ ($json.email || $json.document_id || $json.phone) ? 'sí' : 'no' }}

parameters.jsCode:
const it = $input.item.json;
const em = it.estructura_minima || {};

const text = (v) => String(v ?? '').trim();
const lower = (v) => text(v).toLowerCase();
const isBlankish = (v) => {
  const s = lower(v);
  return !s || ['undefined', 'null', '[null]', 'n/a', 'na', 'sin dato', 'no aplica'].includes(s);
};

const looksLikeEmail = (v) => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(text(v));
const looksLikePhone = (v) => text(v).replace(/\D/g, '').length >= 7;
const looksLikeDoc = (v) => /^[0-9a-zA-Z-]{5,}$/.test(text(v));

const isAnon =
  it.is_anonymous === true ||
  lower(it.is_anonymous) === 'true' ||
  /^an[oó]n/.test(lower(it.citizen_name));

const hasContact =
  (!isBlankish(it.email) && looksLikeEmail(it.email)) ||
  (!isBlankish(it.phone) && looksLikePhone(it.phone)) ||
  (!isBlankish(it.document_id) && looksLikeDoc(it.document_id));

const anonimato_ok = !isAnon || hasContact;

// Fallback defensivo por si algún nodo intermedio no conserva el texto fuente.
let preserved = {};
try {
  preserved = $('Format Preserve (raw/display/llm)').item.json || {};
} catch (e) {
  preserved = {};
}

const srcRaw = text(it.raw_text || preserved.raw_text || '');
const srcDesc = text(it.description || preserved.description || preserved.display_text || '');
const srcSub = text(it.subject || preserved.subject || '');
const sourceOriginal = `${srcRaw} ${srcDesc} ${srcSub}`.toLowerCase().trim();
const hasSourceMaterial = sourceOriginal.length >= 8 && !isBlankish(sourceOriginal);

const rePeticion = /\b(solicit\w+|pido|pedimos|pedir|requier\w+|reclamo|exijo|ruego|interpongo|necesito(?:\s+que)?|quiero(?:\s+que)?|urge(?:\s+que)?|por\s+favor\s+(reparar|resolver|atender|arreglar|intervenir)|repar\w+|arregl\w+|interven\w+|atiend\w+)\b/i;
const hasExplicitVerbOriginal = rePeticion.test(sourceOriginal);

const modelPeticionText = text(it.peticion);
const modelPeticionStrong = em.peticion_ok === true && !isBlankish(modelPeticionText) && rePeticion.test(modelPeticionText.toLowerCase());

const hechosByModel = em.hechos_ok === true && !isBlankish(it.hechos);
const hechosByText = !isBlankish(srcRaw) && srcRaw.length >= 20;
const hechos_ok = hechosByModel || hechosByText;

// Regla: si hay texto fuente, manda el texto fuente; si no lo hay, usamos fallback del modelo.
const peticion_ok = hasSourceMaterial ? hasExplicitVerbOriginal : modelPeticionStrong;

const respeto_ok = it.is_offensive === true ? false : (it.respeto_ok !== false);

const gates = {
  hechos_ok,
  peticion_ok,
  respeto_ok,
  anonimato_ok,
};

const gate_fail_reasons = [];
if (!gates.hechos_ok) gate_fail_reasons.push('faltan_hechos');
if (!gates.peticion_ok) gate_fail_reasons.push('falta_peticion');
if (!gates.respeto_ok) gate_fail_reasons.push('irrespetuoso');
if (!gates.anonimato_ok) gate_fail_reasons.push('anonimo_sin_datos_contacto');

const passes_validity = gate_fail_reasons.length === 0;

return {
  ...it,
  gates,
  gate_fail_reasons,
  anonimato: isAnon,
  passes_validity,
  debug_gate: {
    isAnon,
    hasContact,
    hasSourceMaterial,
    hasExplicitVerbOriginal,
    modelPeticionStrong,
    hechosByModel,
    hechosByText,
    respeto_ok,
    test_case: it.test_case ?? null,
  },
};

