const it = $input.item.json;
const g = it.gates || {};
const inputCodes = Array.isArray(it.gate_fail_reasons) ? it.gate_fail_reasons : [];
const codes = [...inputCodes];
const messages = [];

const ensure = (code) => {
  if (!codes.includes(code)) codes.push(code);
};

if (codes.length === 0) {
  if (!g.hechos_ok) ensure('faltan_hechos');
  if (!g.peticion_ok) ensure('falta_peticion');
  if (!g.respeto_ok) ensure('irrespetuoso');
  if (!g.anonimato_ok) ensure('anonimo_sin_datos_contacto');
}

for (const c of codes) {
  if (c === 'faltan_hechos') messages.push('No identificamos hechos concretos en su PQR.');
  if (c === 'falta_peticion') messages.push('No identificamos una petición clara.');
  if (c === 'irrespetuoso') messages.push('La PQR contiene lenguaje no respetuoso.');
  if (c === 'anonimo_sin_datos_contacto') messages.push('Como anónimo no podemos contactarle; aporte un medio de contacto.');
}

if (codes.length === 0) {
  codes.push('fuera_de_competencia_municipal');
  messages.push('La temática parece no corresponder al ámbito municipal.');
}

return { ...it, invalid_reason_codes: codes, invalid_reason_message: messages.join(' ') };

const cls = $('Extraer Clasificación').item.json;
const val = $('Aplicar Compuertas').item.json;
const comunaItem = $input.item.json;

const normUuid = (v) => {
  const s = (v ?? '').toString().trim();
  if (!s || s === 'undefined' || s === 'null') return null;
  return s;
};

const comuna_id = normUuid(comunaItem && comunaItem.id ? comunaItem.id : null);
const secretaria_id = normUuid($('Capturar Secretaría ID').item.json.secretaria_id || null);

const tags = Array.isArray(cls.discriminacion_tematica) ? cls.discriminacion_tematica : [];
const tagSet = new Set(tags.map(t => String(t).toLowerCase()));
const hasTag = (...needles) => needles.some(n => [...tagSet].some(t => t.includes(String(n).toLowerCase())));

const rawTutela = Number(val.tutela_risk_score || cls.tutela_risk_score || 0);
const tutela = Number.isFinite(rawTutela) ? Math.max(0, Math.min(1, rawTutela)) : 0;
const codigo = (cls.secretaria_codigo || '').toUpperCase();
const tipo = cls.tipo || 'peticion';

let level = 'P3_baja';
let score = 25;
const reasons = [];

if (hasTag('vulnerabilidad:menor', 'vulnerabilidad:menor-de-edad', 'vulnerabilidad:adulto-mayor', 'vulnerabilidad:persona-con-discapacidad', 'vulnerabilidad:mujer-embarazada')) {
  level = 'P0_critica'; score = 95; reasons.push('población vulnerable identificada');
}
if (codigo === 'SSAL' && (hasTag('urgente') || tutela >= 0.7)) {
  level = 'P0_critica'; score = Math.max(score, 92); reasons.push('salud + urgencia');
}
if (codigo === 'DAGRD') {
  level = 'P0_critica'; score = Math.max(score, 90); reasons.push('gestión del riesgo de desastres');
}
if (level !== 'P0_critica') {
  if (codigo === 'SSEG' || codigo === 'SSAL' || tipo === 'denuncia' || tutela >= 0.5) {
    level = 'P1_alta'; score = 75; reasons.push(`competencia crítica ${codigo} o riesgo tutela ${tutela}`);
  } else if (['SINF','SMOV','SMAM','SGOB'].includes(codigo) || tipo === 'reclamo' || tipo === 'queja') {
    level = 'P2_media'; score = 55; reasons.push(`competencia operativa ${codigo} (${tipo})`);
  } else {
    level = 'P3_baja'; score = 30; reasons.push(`trámite administrativo ${codigo} (${tipo})`);
  }
}

const HOLIDAYS_CO = new Set(['2025-01-01','2025-01-06','2025-03-24','2025-04-17','2025-04-18','2025-05-01','2025-06-02','2025-06-23','2025-06-30','2025-07-20','2025-08-07','2025-08-18','2025-10-13','2025-11-03','2025-11-17','2025-12-08','2025-12-25','2026-01-01','2026-01-12','2026-03-23','2026-04-02','2026-04-03','2026-05-01','2026-05-18','2026-06-08','2026-06-15','2026-06-29','2026-07-20','2026-08-07','2026-08-17','2026-10-12','2026-11-02','2026-11-16','2026-12-08','2026-12-25']);

const dayMs = 24 * 60 * 60 * 1000;
const businessDays = level === 'P0_critica' ? 1 : level === 'P1_alta' ? 5 : level === 'P2_media' ? 15 : 30;
let d = new Date(val.issued_at || val.created_at || Date.now());
if (Number.isNaN(d.getTime())) d = new Date();

let added = 0;
while (added < businessDays) {
  d = new Date(d.getTime() + dayMs);
  const dow = d.getUTCDay();
  const ymd = d.toISOString().slice(0,10);
  if (dow !== 0 && dow !== 6 && !HOLIDAYS_CO.has(ymd)) added += 1;
}
const legal_deadline = d.toISOString();

return [{
  ...val,
  ...cls,
  secretaria_id,
  comuna_id,
  priority_level: level,
  priority_score: score,
  priority_reason: { rules: reasons, tutela_risk_score: tutela, business_days: businessDays },
  legal_deadline
}];
